// Pull both ensures conjuncts into the proof context so z3 sees them as
// ground facts (not just universally-quantified obligations on r1 / r2).
assert(r1@ == Map::<AbstractEndPoint, V>::empty());
assert(r2@ == Map::<AbstractEndPoint, V>::empty());

// Transitivity through the shared right-hand side `Map::empty()` lines up
// the two `@` instantiations on a single common expression — this is the
// trigger gap the file-level z3 run was missing.
assert(r1@ == r2@);

// Map extensional equality form, in case `det_new_equal` reduces via the
// view's `=~=` (Map ext-equal) rather than plain `==`.
assert(r1@ =~= r2@);
